1	// compose.js - THE composition engine (design rev 5 S5.2 Rules 1-4; spec
2	// YB-6). Pure functions only: no DOM, no fetch, no clock reads - every
3	// input is a value already on the wire (a lane's position/freshness, the
4	// current snapshot's vocabularies.positions defs, and whether a renderer
5	// exists for this lane's payload shape). That purity is what makes the
6	// THREE-AXIS matrix (board/web/test/compose.test.js) exhaustively testable
7	// in Node with no browser.
8	import { describeVocab } from './vocab.js';
9	
10	// The ONLY closed taxonomy (design S5.2) and its severity order. Growing
11	// this set is a constitution-level decision (schema/yard-snapshot.schema.json
12	// $defs.register's own description says the same).
13	export const REGISTER_ORDER = ['nominal', 'in-progress', 'needs-attention'];
14	
15	function rank(register) {
16	  const i = REGISTER_ORDER.indexOf(register);
17	  // An unrecognised register STRING (not id - a register value itself)
18	  // is a discovery, not a silent "calm" - never let unknown sort as fine.
19	  return i === -1 ? REGISTER_ORDER.length : i;
20	}
21	
22	// Rule 1: rendered register = MOST SEVERE of the axes given.
23	export function mostSevereRegister(...registers) {
24	  return registers.reduce((worst, r) => (rank(r) > rank(worst) ? r : worst), REGISTER_ORDER[0]);
25	}
26	
27	// Position's register: from its def (vocabularies.positions); an
28	// unrecognised position id renders needs-attention (design Rule 1: "needs-
29	// attention if unrecognised").
30	export function positionRegister(positionId, positionDefs) {
31	  return describeVocab(positionId, positionDefs).register;
32	}
33	
34	// Freshness's register: the design's closed mapping (S5.2):
35	// not-applicable -> nominal, never-polled -> in-progress, fresh -> nominal,
36	// stale -> needs-attention, failed -> needs-attention.
37	const FRESHNESS_REGISTER = {
38	  'not-applicable': 'nominal',
39	  'never-polled': 'in-progress',
40	  fresh: 'nominal',
41	  stale: 'needs-attention',
42	  failed: 'needs-attention'
43	};
44	
45	export function freshnessRegister(freshness) {
46	  const kind = freshness && freshness.kind;
47	  return Object.prototype.hasOwnProperty.call(FRESHNESS_REGISTER, kind)
48	    ? FRESHNESS_REGISTER[kind]
49	    : 'needs-attention'; // an unrecognised freshness kind is a discovery too, never silence
50	}
51	
52	// Capability's register: no renderer for this lane's payload shape resolves
53	// needs-attention - design Rule 1's load-bearing case: a live lane whose
54	// data source dies (or whose payload shape this view does not know how to
55	// render) resolves hot even when position and freshness both read calm.
56	export function capabilityRegister(hasRenderer) {
57	  return hasRenderer ? 'nominal' : 'needs-attention';
58	}
59	
60	/**
61	 * The THREE-AXIS matrix function YB-6 pins: position register x freshness
62	 * kind x capability present/absent, most-severe-wins.
63	 *
64	 * @param {{position: string, positionDefs: Array, freshness: object, hasRenderer: boolean}} args
65	 */
66	export function composeRegister({ position, positionDefs, freshness, hasRenderer }) {
67	  return mostSevereRegister(
68	    positionRegister(position, positionDefs),
69	    freshnessRegister(freshness),
70	    capabilityRegister(hasRenderer)
71	  );
72	}
73	
74	export const NO_RENDERER_LINE = 'no renderer for this payload';
75	
76	function freshnessLine(freshness) {
77	  const kind = freshness && freshness.kind;
78	  switch (kind) {
79	    case 'not-applicable':
80	      // Rule 2: a lane that will never be read must never say "not yet read".
81	      return null;
82	    case 'never-polled':
83	      return 'not yet polled';
84	    case 'fresh':
85	      // Rule 3: rendered age is ALWAYS server-issued (ageBucketMs), and the
86	      // wire's "fresh" variant carries no ageBucketMs at all - only "stale"
87	      // does (schema/yard-snapshot.schema.json $defs.freshness's oneOf).
88	      // Showing a computed elapsed time here (the mockup's illustrative
89	      // "fresh, 2s ago") would mean computing age from the client's own
90	      // clock off `asOf`, which Rule 3 forbids outright. Disclosed steering
91	      // deviation from the mock's illustrative text; the contract wins.
92	      return 'fresh';
93	    case 'stale': {
94	      const bucketSeconds = Math.round((freshness.ageBucketMs || 0) / 1000);
95	      return `stale, ${bucketSeconds}s`;
96	    }
97	    case 'failed': {
98	      const reason = freshness.reason || {};
99	      const label = reason.detail || reason.code || 'source failed';
100	      return freshness.lastGoodAsOf
101	        ? `source failed (${label}) - showing last good from ${freshness.lastGoodAsOf}`
102	        : `source failed (${label}) - no good data has ever been read`;
103	    }
104	    default:
105	      // Freshness is closed BY MECHANISM (design S5.2), but this module
106	      // never assumes a closed set holds at the wire boundary: an
107	      // unrecognised kind renders hot, by name - the same discovery
108	      // treatment applied to positions and outcomes elsewhere.
109	      return `unrecognised freshness: '${kind}'`;
110	  }
111	}
112	
113	/**
114	 * Rule 2: position speaks first (primary line), freshness second;
115	 * not-applicable renders NO freshness line; missing capability says "no
116	 * renderer for this payload", never nothing.
117	 *
118	 * @param {{position: string, positionDefs: Array, freshness: object, hasRenderer: boolean}} args
119	 */
120	export function composeLines({ position, positionDefs, freshness, hasRenderer }) {
121	  const described = describeVocab(position, positionDefs);
122	  const primary = described.recognised ? described.label : `unrecognised position: '${position}'`;
123	
124	  let secondary = freshnessLine(freshness);
125	
126	  if (!hasRenderer) {
127	    secondary = secondary ? `${secondary} - ${NO_RENDERER_LINE}` : NO_RENDERER_LINE;
128	  }
129	
130	  return { primary, secondary };
131	}
