1	// render.js - the pure view-model builder (task 5.3). Turns a validated
2	// wire snapshot into plain-object view state; app.js's DOM writer (the only
3	// impure consumer) walks this shape. No DOM here on purpose: this keeps
4	// the composition-and-vocabulary logic testable in Node against real
5	// captured payloads (board/web/test/fixtures/real-snapshot.json).
6	import { composeRegister, composeLines } from './compose.js';
7	import { hasRendererFor } from './lanes.js';
8	import { describeVocab } from './vocab.js';
9	
10	/**
11	 * Completeness guard (design rev 5 S5.2), restated at the view: the
12	 * mockup's "a lane count ... so a silently missing lane is detectable" is
13	 * only true if the view actually COMPARES the declared count
14	 * (config.laneCount) against what it observed, rather than only echoing
15	 * one of the two numbers.
16	 */
17	export function checkLaneCompleteness(snapshot) {
18	  const declared = snapshot.config.laneCount;
19	  const observed = snapshot.lanes.length;
20	  return { declared, observed, mismatch: declared !== observed };
21	}
22	
23	/**
24	 * @param {object} snapshot - a snapshot already validated against
25	 *   schema/yard-snapshot.schema.json (task 5.2's ingest.js gate).
26	 * @param {Array<{code:string, detail:string, register:string}>} clientConditions
27	 *   - board conditions raised BY THE VIEW itself (e.g. a discarded
28	 *   payload, a disconnect) - merged alongside the server's own `board`
29	 *   array, never replacing it.
30	 */
31	export function buildBoardViewModel(snapshot, clientConditions = []) {
32	  const vocab = snapshot.vocabularies;
33	  const completeness = checkLaneCompleteness(snapshot);
34	
35	  // Rule 4 (design S5.2): a board condition's register is authoritative
36	  // from the server - the view NEVER recomputes it, only renders it.
37	  const boardConditions = [...snapshot.board, ...clientConditions];
38	  if (completeness.mismatch) {
39	    boardConditions.push({
40	      code: 'view-lane-count-mismatch',
41	      detail: `chrome declares ${completeness.declared} lane(s) but the snapshot carried ${completeness.observed}`,
42	      register: 'needs-attention'
43	    });
44	  }
45	
46	  const lanes = snapshot.lanes.map((lane) => {
47	    const hasRenderer = hasRendererFor(lane);
48	    const register = composeRegister({ position: lane.position, positionDefs: vocab.positions, freshness: lane.freshness, hasRenderer });
49	    const lines = composeLines({ position: lane.position, positionDefs: vocab.positions, freshness: lane.freshness, hasRenderer });
50	    return {
51	      id: lane.id,
52	      title: lane.title,
53	      register,
54	      primary: lines.primary,
55	      secondary: lines.secondary,
56	      body: buildLaneBody(lane, vocab, hasRenderer)
57	    };
58	  });
59	
60	  return {
61	    asOf: snapshot.asOf,
62	    demoMode: Boolean(snapshot.config.demoMode),
63	    laneCompleteness: completeness,
64	    boardConditions,
65	    lanes
66	  };
67	}
68	
69	function buildLaneBody(lane, vocab, hasRenderer) {
70	  if (!hasRenderer) {
71	    return { kind: 'no-renderer' };
72	  }
73	
74	  switch (lane.id) {
75	    case 'trains':
76	      return {
77	        kind: 'trains',
78	        trains: lane.data.trains.map((t) => ({
79	          id: t.id,
80	          title: t.title,
81	          declaredNotObserved: t.declaredNotObserved || [],
82	          cars: t.cars.map((c) => ({
83	            subject: c.subject,
84	            role: describeVocab(c.role, vocab.roles), // presentational label OK - a structural descriptor, not a data value
85	            gate: c.gate ?? null,
86	            // VERBATIM, never translated (mockup brief: "the real board
87	            // renders whatever state word its data source provides,
88	            // VERBATIM, never a translation of it") - describeVocab is
89	            // used ONLY for the register (color), never the displayed text.
90	            state: c.state,
91	            stateRegister: describeVocab(c.state, vocab.liveness).register,
92	            outcome: c.outcome ?? null,
93	            outcomeRegister: c.outcome ? describeVocab(c.outcome, vocab.outcomes).register : null,
94	            at: c.at,
95	            superseded: c.superseded || []
96	          }))
97	        }))
98	      };
99	    case 'gates':
100	      return {
101	        kind: 'gates',
102	        gates: lane.data.gates.map((g) => ({
103	          name: g.name,
104	          subject: g.subject,
105	          outcome: g.outcome, // VERBATIM - "REJECT" stays "REJECT" (spec YB-5: rendered VERBATIM, never re-derived)
106	          outcomeRegister: describeVocab(g.outcome, vocab.outcomes).register,
107	          at: g.at
108	        }))
109	      };
110	    case 'dispatches': {
111	      const dispatches = lane.data.dispatches.map((d) => ({
112	        subject: d.subject,
113	        state: d.state, // VERBATIM
114	        stateRegister: describeVocab(d.state, vocab.liveness).register,
115	        at: d.at,
116	        outcome: d.outcome ?? null,
117	        elapsedSeconds: typeof d.elapsed_seconds === 'number' ? d.elapsed_seconds : null,
118	        budgetSeconds: typeof d.budget_seconds === 'number' ? d.budget_seconds : null,
119	        budgetSource: d.budget_source ?? null,
120	        assigned: Boolean(d.assigned)
121	      }));
122	      return {
123	        kind: 'dispatches',
124	        dispatches,
125	        // Yard inventory (mockup: "visible, never hidden") - the count is
126	        // ALWAYS surfaced, even at zero, so its absence is never mistaken
127	        // for "nothing to disclose".
128	        yardInventoryCount: dispatches.filter((d) => !d.assigned).length
129	      };
130	    }
131	    case 'freight':
132	      // Dark: no adapter exists (Car 4's adjudication: "no-equipment",
133	      // distinguished from fuel's "bagged" below).
134	      return { kind: 'dark', text: 'no equipment on this lane' };
135	    case 'fuel':
136	      // Bagged: data exists (cost fields on some records) but is
137	      // deliberately not surfaced yet (#11) - the hooded-signal treatment,
138	      // distinct text from freight's dark absence.
139	      return { kind: 'bagged', text: 'data held, not surfaced' };
140	    default:
141	      // hasRendererFor already gates this branch to only the five known
142	      // ids when it returns true, so this default is defensive dead code
143	      // for a future lane id added to EXPECTED_LANE_IDS without a body
144	      // case here yet - never silently blank.
145	      return { kind: 'unknown-lane', raw: lane.data ?? null };
146	  }
147	}
