1	// dom-writer.js - the ONLY module that touches the DOM. Takes render.js's
2	// pure view model and a `document`-shaped object (the real browser
3	// `document` in production; a minimal hand-rolled shim in
4	// board/web/test/dom-writer.test.js) and writes it into `root`.
5	//
6	// Deliberately uses only createElement/appendChild/textContent/className/
7	// setAttribute - the smallest DOM surface that can express this board -
8	// so the same code runs unmodified against Node's test shim (task 5.5's
9	// "render into a minimal DOM shim").
10	//
11	// Visual authority (plan task 5.3): the reviewed mockup brief
12	// (docs/design/2026-07-23-ui-mockup-brief.md) and design rev 5 S5.2's
13	// composition rules BIND (three registers only, verbatim words, honesty
14	// chrome, bagged/dark dignity); the 2b track-schematic (trains/gates) +
15	// 1b Solari-board (dispatches) mockup merge STEERS. This v0 pass renders
16	// the CONTRACTS fully and the steering direction structurally (track rows
17	// for trains/gates, dense monospace rows for dispatches) rather than
18	// pixel-for-pixel mockup fidelity - disclosed in this car's report as the
19	// conductor's first human look is the actual visual-polish gate.
20	
21	function el(doc, tag, className, text) {
22	  const node = doc.createElement(tag);
23	  if (className) node.className = className;
24	  if (text !== undefined) node.textContent = text;
25	  return node;
26	}
27	
28	function registerClass(register) {
29	  return `register-${register}`;
30	}
31	
32	/**
33	 * @param {Document} doc
34	 * @param {Element} root
35	 * @param {ReturnType<import('./render.js').buildBoardViewModel>} vm
36	 * @param {{connected: boolean}} connection
37	 */
38	export function renderBoard(doc, root, vm, connection) {
39	  root.textContent = ''; // clear() without needing a real DOM API for it
40	
41	  root.appendChild(renderChrome(doc, vm, connection));
42	
43	  const lanesRoot = el(doc, 'section', 'lanes');
44	  for (const lane of vm.lanes) {
45	    lanesRoot.appendChild(renderLane(doc, lane));
46	  }
47	  root.appendChild(lanesRoot);
48	}
49	
50	function renderChrome(doc, vm, connection) {
51	  const chrome = el(doc, 'header', 'chrome');
52	
53	  if (vm.demoMode) {
54	    chrome.appendChild(el(doc, 'div', 'demo-banner', 'DEMO DATA'));
55	  }
56	
57	  chrome.appendChild(el(doc, 'div', 'as-of', `as of ${vm.asOf ?? '(no successful scan yet)'}`));
58	
59	  const connectionClass = connection.connected ? 'connection-connected' : 'connection-disconnected';
60	  chrome.appendChild(
61	    el(doc, 'div', connectionClass, connection.connected ? 'connected' : 'disconnected - showing last known')
62	  );
63	
64	  const laneCountText = `${vm.laneCompleteness.observed} of ${vm.laneCompleteness.declared} lanes`;
65	  chrome.appendChild(el(doc, 'div', 'lane-count', laneCountText));
66	
67	  if (vm.boardConditions.length > 0) {
68	    const strip = el(doc, 'ul', 'board-conditions');
69	    for (const bc of vm.boardConditions) {
70	      strip.appendChild(el(doc, 'li', `board-condition ${registerClass(bc.register)}`, `${bc.code}: ${bc.detail}`));
71	    }
72	    chrome.appendChild(strip);
73	  }
74	
75	  return chrome;
76	}
77	
78	function renderLane(doc, lane) {
79	  const section = el(doc, 'article', `lane lane-${lane.id} ${registerClass(lane.register)}`);
80	  section.appendChild(el(doc, 'h2', 'lane-title', lane.title));
81	  section.appendChild(el(doc, 'div', 'lane-primary', lane.primary));
82	  if (lane.secondary) {
83	    section.appendChild(el(doc, 'div', 'lane-secondary', lane.secondary));
84	  }
85	  section.appendChild(renderLaneBody(doc, lane.body));
86	  return section;
87	}
88	
89	function renderLaneBody(doc, body) {
90	  switch (body.kind) {
91	    case 'trains':
92	      return renderTrains(doc, body);
93	    case 'gates':
94	      return renderGates(doc, body);
95	    case 'dispatches':
96	      return renderDispatches(doc, body);
97	    case 'dark':
98	      return el(doc, 'div', 'lane-body lane-body-dark', body.text);
99	    case 'bagged':
100	      return el(doc, 'div', 'lane-body lane-body-bagged', body.text);
101	    case 'no-renderer':
102	      return el(doc, 'div', 'lane-body lane-body-no-renderer', 'no renderer for this payload');
103	    default:
104	      return el(doc, 'div', 'lane-body lane-body-unknown', `unrecognised lane body kind: '${body.kind}'`);
105	  }
106	}
107	
108	// TRAINS: track-schematic direction (mockup merge 2b) - each train is a
109	// labeled track holding its cars in sequence.
110	function renderTrains(doc, body) {
111	  const wrap = el(doc, 'div', 'lane-body lane-body-trains');
112	  for (const train of body.trains) {
113	    const track = el(doc, 'div', 'track');
114	    track.appendChild(el(doc, 'div', 'track-title', `${train.title} (${train.id})`));
115	    const cars = el(doc, 'div', 'track-cars');
116	    for (const car of train.cars) {
117	      const chip = el(doc, 'div', `car-chip ${registerClass(car.stateRegister)}`);
118	      chip.appendChild(el(doc, 'span', 'car-subject', car.subject));
119	      chip.appendChild(el(doc, 'span', 'car-role', car.role.label));
120	      // VERBATIM state word - never translated (mockup brief).
121	      chip.appendChild(el(doc, 'span', 'car-state', car.state));
122	      if (car.outcome) {
123	        chip.appendChild(el(doc, 'span', `car-outcome ${registerClass(car.outcomeRegister)}`, car.outcome));
124	      }
125	      if (car.gate) {
126	        chip.appendChild(el(doc, 'span', 'car-gate', car.gate));
127	      }
128	      cars.appendChild(chip);
129	    }
130	    track.appendChild(cars);
131	    if (train.declaredNotObserved.length > 0) {
132	      track.appendChild(
133	        el(doc, 'div', 'declared-not-observed', `declared, not yet observed: ${train.declaredNotObserved.join(', ')}`)
134	      );
135	    }
136	    wrap.appendChild(track);
137	  }
138	  return wrap;
139	}
140	
141	// GATES: signal-head direction (mockup merge 2b) - a small verdict light
142	// per gate, verdict word VERBATIM.
143	function renderGates(doc, body) {
144	  const wrap = el(doc, 'div', 'lane-body lane-body-gates');
145	  for (const gate of body.gates) {
146	    const signal = el(doc, 'div', `signal ${registerClass(gate.outcomeRegister)}`);
147	    signal.appendChild(el(doc, 'span', 'signal-name', gate.name));
148	    signal.appendChild(el(doc, 'span', 'signal-outcome', gate.outcome)); // VERBATIM
149	    signal.appendChild(el(doc, 'span', 'signal-at', gate.at));
150	    wrap.appendChild(signal);
151	  }
152	  return wrap;
153	}
154	
155	// DISPATCHES: Solari split-flap direction (mockup merge 1b) - dense
156	// monospace rows: subject, state word, elapsed.
157	function renderDispatches(doc, body) {
158	  const wrap = el(doc, 'div', 'lane-body lane-body-dispatches');
159	  wrap.appendChild(
160	    el(doc, 'div', 'yard-inventory-count', `${body.yardInventoryCount} in yard inventory (unassigned)`)
161	  );
162	  const rows = el(doc, 'div', 'solari-rows');
163	  for (const d of body.dispatches) {
164	    const row = el(doc, 'div', `solari-row ${registerClass(d.stateRegister)}${d.assigned ? '' : ' unassigned'}`);
165	    row.appendChild(el(doc, 'span', 'solari-subject', d.subject));
166	    row.appendChild(el(doc, 'span', 'solari-state', d.state)); // VERBATIM
167	    if (d.elapsedSeconds !== null) {
168	      row.appendChild(el(doc, 'span', 'solari-elapsed', `${d.elapsedSeconds}s`));
169	    }
170	    rows.appendChild(row);
171	  }
172	  wrap.appendChild(rows);
173	  return wrap;
174	}
