1	/* board.css - StarCar yard board (task 5.3). Industrial CTC-panel direction
2	   (mockup brief + the owner's 2b/1b merge): dark background, dense
3	   monospace typography, color rationed to exactly three registers.
4	
5	   Steering deviation, disclosed: the mockup direction names IBM Plex Mono /
6	   Barlow Condensed specifically. This v0 pass uses system monospace /
7	   condensed-sans font STACKS with no network font fetch (no Google Fonts
8	   CDN), so the board is fully self-contained and renders offline/in CI
9	   with no external dependency. Swapping in the named webfonts is a pure
10	   CSS change whenever that's wanted - never a re-architecture.
11	
12	   The one hard aesthetic law (mockup brief): three severity colors, total.
13	   Every other color in this file is background/structure/typography, never
14	   a fourth "shade of alarm". */
15	
16	:root {
17	  --bg: #14181d;
18	  --panel: #1c2128;
19	  --border: #2c333d;
20	  --text: #d9d5c9; /* paper, mockup's nominal ink color */
21	  --text-dim: #8a8f97;
22	
23	  --nominal: #d9d5c9;
24	  --in-progress: #ffb454; /* amber, mockup's in-progress color */
25	  --needs-attention: #ff4a3a; /* red, mockup's needs-attention color */
26	}
27	
28	* {
29	  box-sizing: border-box;
30	}
31	
32	body {
33	  margin: 0;
34	  background: var(--bg);
35	  color: var(--text);
36	  font-family: 'IBM Plex Mono', ui-monospace, 'Cascadia Mono', 'Consolas', monospace;
37	}
38	
39	#board-root {
40	  max-width: 1400px;
41	  margin: 0 auto;
42	  padding: 1rem;
43	}
44	
45	/* --- honesty chrome ------------------------------------------------- */
46	
47	.chrome {
48	  display: flex;
49	  flex-wrap: wrap;
50	  gap: 1rem;
51	  align-items: center;
52	  padding: 0.5rem 0.75rem;
53	  border-bottom: 2px solid var(--border);
54	  margin-bottom: 1rem;
55	  font-family: 'Barlow Condensed', ui-sans-serif, system-ui, sans-serif;
56	  letter-spacing: 0.02em;
57	}
58	
59	.demo-banner {
60	  background: var(--in-progress);
61	  color: #14181d;
62	  font-weight: 700;
63	  padding: 0.15rem 0.6rem;
64	  border-radius: 2px;
65	}
66	
67	.connection-disconnected {
68	  color: var(--needs-attention);
69	  font-weight: 700;
70	}
71	
72	.connection-connected {
73	  color: var(--text-dim);
74	}
75	
76	.board-conditions {
77	  list-style: none;
78	  margin: 0.25rem 0 0 0;
79	  padding: 0;
80	  width: 100%;
81	  display: flex;
82	  flex-direction: column;
83	  gap: 0.15rem;
84	  font-size: 0.85rem;
85	}
86	
87	.board-condition {
88	  padding: 0.1rem 0.4rem;
89	  border-left: 3px solid var(--border);
90	}
91	
92	/* --- lanes ------------------------------------------------------------ */
93	
94	.lanes {
95	  display: flex;
96	  flex-direction: column;
97	  gap: 0.75rem;
98	}
99	
100	.lane {
101	  background: var(--panel);
102	  border: 1px solid var(--border);
103	  border-left-width: 6px;
